   const canvasRef = useRef<HTMLCanvasElement>(null);
+  const [agents, setAgents] = useState<AgentInfo[]>(DEFAULT_AGENTS);
+  const [mousePos, setMousePos] = useState<{x: number; y: number} | null>(null);
+  const [hoveredAgent, setHoveredAgent] = useState<{
+    agent: AgentInfo;
+    x: number;
+    y: number;
+  } | null>(null);
+
+  // Token budget used mock (for demo, static value)
+  const TOKEN_BUDGET_USED = 1234;
+
+  // Helper: Draw pixel-art styled tooltip panel
+  function drawTooltip(ctx: CanvasRenderingContext2D, x: number, y: number, lines: string[]) {
+    const padding = 6;
+    const lineHeight = 14;
+    const width = 160;
+    const height = padding * 2 + lines.length * lineHeight;
+
+    // Clamp tooltip position inside canvas
+    const canvas = ctx.canvas;
+    let tx = x + 16;
+    let ty = y + 16;
+    if (tx + width > canvas.width) tx = x - width - 16;
+    if (ty + height > canvas.height) ty = y - height - 16;
+
+    // Background
+    ctx.fillStyle = '#1a1a2e';
+    ctx.fillRect(tx, ty, width, height);
+
+    // Gold border pixel-art style (2px thick)
+    ctx.strokeStyle = '#d4af37';
+    ctx.lineWidth = 2;
+    ctx.strokeRect(tx + 0.5, ty + 0.5, width - 1, height - 1);
+
+    // Text style (parchment)
+    ctx.fillStyle = '#f5deb3';
+    ctx.font = '12px monospace';
+    ctx.textBaseline = 'top';
+    for (let i = 0; i < lines.length; i++) {
+      ctx.fillText(lines[i], tx + padding, ty + padding + i * lineHeight);
+    }
+  }
+
+  // Track mouse move and find hovered agent
+  function onMouseMove(e: React.MouseEvent<HTMLCanvasElement>) {
+    if (!canvasRef.current) return;
+    const rect = canvasRef.current.getBoundingClientRect();
+    const mx = e.clientX - rect.left;
+    const my = e.clientY - rect.top;
+    setMousePos({ x: mx, y: my });
+
+    // Hit test agents
+    // We replicate the agent drawing logic to find their positions and bounds
+    const rc = {
+      width: canvasRef.current.width,
+      height: canvasRef.current.height,
+      ctx: canvasRef.current.getContext('2d')!,
+    };
+    const cols = 3;
+    const padding = 10;
+    const labelH = 24;
+    const roomW = Math.floor((rc.width - padding * (cols + 1)) / cols);
+    const roomH = Math.min(Math.floor(roomW * 0.7), 180);
+
+    const agentsByTier = new Map<string, AgentInfo[]>();
+    for (const a of agents) {
+      const list = agentsByTier.get(a.tier) ?? [];
+      list.push(a);
+      agentsByTier.set(a.tier, list);
+    }
+
+    let foundAgent: { agent: AgentInfo; x: number; y: number } | null = null;
+    outer: for (const slot of ROOM_GRID) {
+      const rx = padding + slot.col * (roomW + padding);
+      const ry = padding + slot.row * (roomH + labelH + padding + 6);
+      const tierAgents = agentsByTier.get(slot.tier) ?? [];
+      const maxVisible = 4;
+      const visible = tierAgents.slice(0, maxVisible);
+      const charScale = Math.min(2.5, roomW / 90);
+
+      for (let i = 0; i < visible.length; i++) {
+        const agent = visible[i];
+        const startX = rx + roomW * 0.15 + i * Math.min(55, (roomW * 0.7) / Math.max(1, visible.length));
+        const startY = ry + labelH + roomH * 0.45;
+
+        // Use getCS to get character position (same as draw)
+        const cs = getCS(agent.id, startX, startY);
+
+        // Character bounding box approx (pixel characters ~32x32 scaled)
+        const w = 32 * charScale;
+        const h = 32 * charScale;
+        const left = cs.x - w / 2;
+        const top = cs.y - h / 2;
+        if (mx >= left && mx <= left + w && my >= top && my <= top + h) {
+          foundAgent = { agent, x: cs.x, y: cs.y };
+          break outer;
+        }
+      }
+    }
+    setHoveredAgent(foundAgent);
+  }
+
