+  useEffect(() => {
+    if (!canvasRef.current) return;
+
+    const cancel = startGameLoop((_dt, frameCount) => {
+      const rc = syncCanvasSize(canvasRef.current!);
+      clearCanvas(rc);
+
+      const cols = 3;
+      const padding = 10;
+      const labelH = 24;
+      const roomW = Math.floor((rc.width - padding * (cols + 1)) / cols);
+      const roomH = Math.min(Math.floor(roomW * 0.7), 180);
+
+      // Group agents by tier
+      const agentsByTier = new Map<string, AgentInfo[]>();
+      for (const a of agents) {
+        const list = agentsByTier.get(a.tier) ?? [];
+        list.push(a);
+        agentsByTier.set(a.tier, list);
+      }
+
+      for (const slot of ROOM_GRID) {
+        const rx = padding + slot.col * (roomW + padding);
+        const ry = padding + slot.row * (roomH + labelH + padding + 6);
+
+        // Room label with shadow
+        drawText(rc, slot.label.toUpperCase(), rx + 5, ry + 15, 11, '#000000');
+        drawText(rc, slot.label.toUpperCase(), rx + 4, ry + 14, 11, COLORS.gold);
+
+        // Room background
+        drawRoom(rc.ctx, slot.tier, rx, ry + labelH, roomW, roomH, frameCount);
+
+        // Room border (double line for depth)
+        rc.ctx.strokeStyle = '#2a2030';
+        rc.ctx.lineWidth = 2;
+        rc.ctx.strokeRect(rx, ry + labelH, roomW, roomH);
+        rc.ctx.strokeStyle = '#5a5a6a';
+        rc.ctx.lineWidth = 1;
+        rc.ctx.strokeRect(rx + 1, ry + labelH + 1, roomW - 2, roomH - 2);
+
+        // Draw agents in this room (cap visible at 4, show overflow badge)
+        const tierAgents = agentsByTier.get(slot.tier) ?? [];
+        const maxVisible = 4;
+        const visible = tierAgents.slice(0, maxVisible);
+        const overflow = tierAgents.length - visible.length;
+        const charScale = Math.min(2.5, roomW / 90);
+        visible.forEach((agent, i) => {
+          // Spread characters within the room's walkable area
+          const startX = rx + roomW * 0.15 + i * Math.min(55, (roomW * 0.7) / Math.max(1, visible.length));
+          const startY = ry + labelH + roomH * 0.45;
+
+          // Update character movement
+          const cs = getCS(agent.id, startX, startY);
+          const walkBounds = {
+            x: rx + roomW * 0.08,
+            y: ry + labelH + roomH * 0.38,
+            w: roomW * 0.84,
+            h: roomH * 0.45,
+          };
+          updateMovement(cs, walkBounds);
+
+          const animState = agent.state as AnimState;
+          drawCharacter(rc.ctx, slot.tier as CharacterType, animState, cs.x, cs.y, charScale, frameCount, agent.id, agent.currentJob);
+
+          // Name plate (below character)
+          const nameY = cs.y + 24 * charScale;
+          drawText(rc, agent.name, cs.x - 4, nameY, 9, COLORS.text);
+          // State badge
+          const stateColor = getStateColor(agent.state);
+          drawText(rc, agent.state, cs.x - 4, nameY + 12, 8, stateColor);
+        });
+
+        // Overflow badge
+        if (overflow > 0) {
+          const badgeX = rx + roomW - 30;
+          const badgeY = ry + labelH + 8;
+          rc.ctx.fillStyle = '#4a2060';
+          rc.ctx.fillRect(badgeX, badgeY, 24, 14);
+          rc.ctx.strokeStyle = COLORS.gold;
+          rc.ctx.lineWidth = 1;
+          rc.ctx.strokeRect(badgeX, badgeY, 24, 14);
+          drawText(rc, `+${overflow}`, badgeX + 3, badgeY + 11, 9, COLORS.gold);
+        }
+
+        if (tierAgents.length === 0) {
+          drawText(rc, '— vacant —', rx + roomW * 0.3, ry + labelH + roomH * 0.55, 10, '#555');
+        }
+      }
+
+      // Draw tooltip if hovered
+      if (hoveredAgent) {
+        const { agent, x, y } = hoveredAgent;
+        const lines = [
+          `${agent.name} (${agent.tier})`,
+          `Status: ${agent.state}`,
+          `Task: ${agent.currentJob ?? 'Idle'}`,
+          `Tokens used: ${TOKEN_BUDGET_USED}`,
+        ];
+        drawTooltip(rc.ctx, x, y, lines);
+      }
+    });
+
+    return cancel;
+  }, [agents, hoveredAgent]);

